const items = $input.all();
const response = items[0].json;

const now = new Date();
const billingMonth = now.getMonth() === 0
  ? `${now.getFullYear() - 1}-12`
  : `${now.getFullYear()}-${String(now.getMonth()).padStart(2, '0')}`;

let tenants = Array.isArray(response) ? response
  : (response.tenants || response.data || response.items || []);

const activeTenants = tenants.filter(t =>
  (t.status || '').toLowerCase() === 'active'
  || (t.active === true)
  || (t.enabled === true)
);

return activeTenants.map(tenant => ({
  json: {
    tenant_id: tenant.tenant_id || tenant.id,
    tenant_name: tenant.name || tenant.tenant_name,
    contact_email: tenant.billing_email || tenant.contact_email || tenant.email,
    plan: tenant.plan || tenant.subscription_plan || 'standard',
    billing_month: billingMonth,
    currency: tenant.currency || 'USD'
  }
}));

const billingResult = $input.item.json;
const tenantData = $('Process Each Tenant').item.json;

const lineItems = billingResult.line_items || billingResult.items || [];
const subtotal = billingResult.subtotal || billingResult.amount || 0;
const tax = billingResult.tax || (subtotal * 0.1);
const total = billingResult.total || (subtotal + tax);

return [{
  json: {
    tenant_id: tenantData.tenant_id,
    tenant_name: tenantData.tenant_name,
    contact_email: tenantData.contact_email,
    billing_month: tenantData.billing_month,
    plan: tenantData.plan,
    currency: tenantData.currency,
    line_items: lineItems,
    subtotal: Math.round(subtotal * 100) / 100,
    tax: Math.round(tax * 100) / 100,
    total: Math.round(total * 100) / 100,
    invoice_date: new Date().toISOString(),
    due_date: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString(),
    status: 'pending',
    raw_calculation: billingResult
  }
}];

const allItems = $input.all();

const now = new Date();
const billingMonth = allItems[0]?.json?.billing_month || `${now.getFullYear()}-${String(now.getMonth()).padStart(2,'0')}`;

let totalRevenue = 0;
let invoiceCount = 0;
const tenantSummaries = [];
const failedTenants = [];

for (const item of allItems) {
  const invoice = $('Format Invoice').all().find(
    i => i.json.tenant_id === item.json.tenant_id
  )?.json;

  if (invoice) {
    totalRevenue += invoice.total || 0;
    invoiceCount++;
    tenantSummaries.push({
      tenant_id: invoice.tenant_id,
      tenant_name: invoice.tenant_name,
      plan: invoice.plan,
      total: invoice.total,
      currency: invoice.currency,
      email_sent: item.json.id !== undefined
    });
  } else {
    failedTenants.push({
      tenant_id: item.json.tenant_id || 'unknown',
      reason: 'invoice_not_found'
    });
  }
}

return [{
  json: {
    report_type: 'monthly_billing_summary',
    billing_month: billingMonth,
    generated_at: new Date().toISOString(),
    total_invoices: invoiceCount,
    total_revenue: Math.round(totalRevenue * 100) / 100,
    currency: 'USD',
    failed_tenants: failedTenants,
    tenant_summaries: tenantSummaries
  }
}];
